#include<bits/stdc++.h>
using namespace std;
const int N=1e5+10;
int a[N],b[N],d[N];
int n,l,c;
long long ans;
void msort(int l,int r)
{
	if(l>=r)
	{
		return;
	}
	int mid=(l+r)/2;
	msort(l,mid);
	msort(mid+1,r);
	int i=l,j=mid+1,tot=l;
	while(i<=mid&&j<=r)
	{
		if(a[i]<=a[j])
		{
			b[tot++]=a[i++];
		}
		else
		{
			b[tot++]=a[j++];
			ans-=mid-i+1;
		}
	}
	while(i<=mid)
	{
		b[tot++]=a[i++];
	}
	while(j<=r)
	{
		b[tot++]=a[j++];
	}
	for(int k=l;k<=r;k++)
	{
		a[k]=b[k];
	}
}
int main()
{
	scanf("%d%d%d",&n,&l,&c);
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&d[i]);
	}
	sort(d+1,d+1+n);
	long long temp=0,temp1;
	for(int i=1;i<=n;i++)
	{
		temp1=(long long)l*d[i]/d[n];
		a[i]=(long long)l*d[i]%d[n];
		ans+=temp1*(i-1)-temp;
		temp+=temp1;
	}
	msort(1,n);
	printf("%lld",ans);
	return 0;
}
